package main

import (
	"fmt"
	"net/mail"
	"net/smtp"
	"strings"
	"html"
)

// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body that contains the user feedback. The returned emailBody
// can be passed directly to smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses using net/mail
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Escape user‑provided fields for safe inclusion in HTML
	// (prevent XSS in the generated email)
	safeUserName := html.EscapeString(strings.TrimSpace(userName))
	safeSubject := html.EscapeString(strings.TrimSpace(subject))
	safeFeedback := html.EscapeString(feedbackContent)

	// Build the Subject header. If it contains non‑ASCII characters we could
	// encode it using MIME encoded‑word, but for simplicity we assume ASCII.
	headerSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Build the RFC 5322 headers
	// Note: each header line must end with CRLF (“\r\n”)
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		headerSubject,
	)

	// HTML body – we put the feedback inside a <pre> element to preserve whitespace.
	// Because we already escaped the raw content we can safely embed it.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedback,
	)

	// Assemble the complete message (headers + body)
	emailMessage := headers + htmlBody

	// The net/smtp package expects the message as a []byte,
	// but we return the string form – callers can convert it
	// with []byte(emailBody) when calling smtp.SendMail.
	return emailMessage, nil
}

