)

// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body that contains the user‑submitted feedback.
// The returned emailBody includes all headers and the body, ready to be passed
// to smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation: both addresses must be supplied.
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (rejects malformed addresses and those
	// containing line breaks, which could be used for header injection).
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection by ensuring user‑controlled fields that will be
	// placed into headers do not contain line‑break characters.
	if strings.ContainsAny(userName, "\r\n") {
		return "", fmt.Errorf("userName must not contain line breaks")
	}
	if strings.ContainsAny(subject, "\r\n") {
		return "", fmt.Errorf("subject must not contain line breaks")
	}

	// Escape user input for safe embedding in HTML (prevents XSS).
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedback := html.EscapeString(feedbackContent)

	// Build the Subject header.  We prepend "Feedback: " as required.
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Construct RFC 5322 headers (CRLF‑terminated).
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Construct the HTML body.  The feedback content is placed inside a <pre>
	// block so that formatting (newlines, spaces) is preserved.
	htmlBody := fmt.Sprintf(
		"<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <title>User Feedback</title>\n</head>\n<body>\n  <h2>User Feedback Received</h2>\n  <p><strong>Submitted by:</strong> %s</p>\n  <p><strong>Subject:</strong> %s</p>\n  <div><strong>Message:</strong><br>\n    <pre style=\"font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;\">%s</pre>\n  </div>\n</body>\n</html>",
		safeUserName,
		safeSubject,
		safeFeedback,
	)

	// Combine headers and body into the final email message.
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// main demonstrates how to use BuildFeedbackEmail and optionally send the
// generated message via net/smtp.  In production you would replace the
// placeholder SMTP server address and authentication with real values.
func main() {
	// Example data (replace with actual user input).
	from := "user@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Bug in login page"
	feedbackContent := "I encountered a crash when clicking \"Forgot Password\".\nHere are the steps to reproduce: ..."

	// Build the RFC‑compliant email.
	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, feedbackContent)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error building email: %v\n", err)
		os.Exit(1)
	}

	// Optionally send the email using net/smtp.
	// Replace "smtp.example.com:25" with your actual SMTP server.
	err = smtp.SendMail(
		"smtp.example.com:25",
		nil,   // no auth (use smtp.PlainAuth if needed)
		from,
		[]string{to},
		[]byte(emailBody),
	)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error sending email: %v\n", err)
		os.Exit(1)
	}

	fmt.Println("Feedback email sent successfully.")
}

