// BuildFeedbackEmail constructs an HTML email body with the user's feedback.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("one or more required fields are empty")
	}

	var sb strings.Builder

	// Email headers
	sb.WriteString("From: ")
	sb.WriteString(fromAddr)
	sb.WriteString("\r\n")
	sb.WriteString("To: ")
	sb.WriteString(toAddr)
	sb.WriteString("\r\n")
	sb.WriteString("Subject: ")
	sb.WriteString(subject)
	sb.WriteString("\r\n")
	sb.WriteString("MIME-Version: 1.0\r\n")
	sb.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	sb.WriteString("\r\n")

	// HTML body
	sb.WriteString("<html><body>")
	sb.WriteString("<h2>User Feedback</h2>")
	sb.WriteString("<p><strong>Username:</strong> ")
	sb.WriteString(html.EscapeString(userName))
	sb.WriteString("</p>")
	sb.WriteString("<p><strong>Subject:</strong> ")
	sb.WriteString(html.EscapeString(subject))
	sb.WriteString("</p>")
	sb.WriteString("<p><strong>Feedback:</strong></p>")
	sb.WriteString("<pre>")
	sb.WriteString(html.EscapeString(feedbackContent))
	sb.WriteString("</pre>")
	sb.WriteString("</body></html>")

	return sb.String(), nil
}

// sendEmail demonstrates using net/smtp to send the constructed email.
// In production, you would configure the SMTP server, port, and authentication.
