package main

import (
	"fmt"
	"net/mail"
	"strings"
	"html"
)

// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body containing the user‑submitted feedback.
// The returned emailBody includes the headers and the body, ready to be
// sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation – sender and recipient must be provided
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Trim surrounding whitespace
	fromAddr = strings.TrimSpace(fromAddr)
	toAddr = strings.TrimSpace(toAddr)

	// Validate email address format using the standard library
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize the user‑provided subject to prevent header injection.
	// It must be a single line without any line breaks or control characters.
	sanitizedSubject := sanitizeSubject(subject)
	if sanitizedSubject == "" {
		return "", fmt.Errorf("subject cannot be empty after sanitization")
	}

	// Escape user input for safe inclusion in the HTML body
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(sanitizedSubject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// Build the Subject header – note that we use the already sanitized subject
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	// Construct the MIME headers
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Build the HTML body
	htmlBody := fmt.Sprintf(
		"<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <title>User Feedback</title>\n</head>\n<body>\n  <h2>User Feedback Received</h2>\n  <p><strong>Submitted by:</strong> %s</p>\n  <p><strong>Subject:</strong> %s</p>\n  <div><strong>Message:</strong><br>\n    <pre style=\"font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;\">%s</pre>\n  </div>\n</body>\n</html>",
		safeUserName,
		safeSubject,
		safeFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody
	return emailMessage, nil
}

// sanitizeSubject removes any line‑break characters, collapses multiple spaces,
// trims whitespace, and limits the length to a reasonable size (200 characters).
// This prevents CRLF injection and ensures the header remains a single line.
func sanitizeSubject(s string) string {
	// Replace line breaks with a space
	s = strings.ReplaceAll(s, "\r\n", " ")
	s = strings.ReplaceAll(s, "\n", " ")
	s = strings.ReplaceAll(s, "\r", " ")

	// Remove control characters (ASCII < 0x20 except TAB, LF, CR) and DEL (0x7F)
	var sb strings.Builder
	sb.Grow(len(s))
	for _, r := range s {
		if r == 0x9 || r == 0xA || r == 0xD || (r >= 0x20 && r != 0x7F) {
			sb.WriteRune(r)
		}
	}
	s = sb.String()

	// Collapse multiple spaces into one and trim
	s = strings.Join(strings.Fields(s), " ")
	s = strings.TrimSpace(s)

	// Limit length
	const maxLen = 200
	if len(s) > maxLen {
		s = s[:maxLen]
	}
	return s
}

// Example (optional) main to demonstrate usage
func main() {
	email, err := BuildFeedbackEmail(
		"sender@example.com",
		"support@example.com",
		"John Doe",
		"Login issue",
		"I cannot log in to my account after resetting the password.",
	)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Println("Generated email:")
	fmt.Println(email)
}

