// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body containing the user feedback. The returned emailBody
// includes all headers and the body, ready to be passed to smtp.SendMail.
// It performs input validation and sanitisation to prevent email header
// injection and XSS attacks.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// ---- Basic validation -------------------------------------------------
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Verify that the addresses conform to the RFC 5322 address specification.
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// ---- Sanitise user‑supplied header values -----------------------------
	// The subject line must be a single line without any line‑breaks.
	subject = sanitizeHeaderValue(subject)

	// ---- Build the RFC 5322 header block ----------------------------------
	// "Feedback: " is added to the subject for clarity.
	header := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: Feedback: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		subject,
	)

	// ---- Escape user input for the HTML body ------------------------------
	// html.EscapeString prevents injection of HTML/JavaScript.
	safeUserName := html.EscapeString(userName)
	safeSubject   := html.EscapeString(subject)
	safeContent   := html.EscapeString(feedbackContent)

	// Construct the HTML body. The feedback content is wrapped in a <pre>
	// block to preserve whitespace; any HTML tags inside the content have
	// already been escaped above.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// ---- Combine headers and body -----------------------------------------
	emailBody = header + htmlBody
	return emailBody, nil
}

// sanitizeHeaderValue removes all control characters (including CR/LF)
// from a string so that it can safely be placed in an SMTP header.
func sanitizeHeaderValue(v string) string {
	// Replace any newline or carriage‑return with a space.
	v = strings.ReplaceAll(v, "\r\n", " ")
	v = strings.ReplaceAll(v, "\r", " ")
	v = strings.ReplaceAll(v, "\n", " ")
	// Strip all other control characters.
	re := regexp.MustCompile(`[[:cntrl:]]`)
	return re.ReplaceAllString(v, "")
}

// main demonstrates how to use BuildFeedbackEmail and send the message
// via an SMTP server. In production this part would be driven by config
// and proper error handling.
func main() {
	from    := "feedback@example.com"
	to      := "support@example.com"
	user    := "John Doe"
	subject := "Login issue"
