package main

import (
	"fmt"
	"html"
	"net/mail"
)

// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body containing the user feedback information.
// The returned emailBody includes headers and the HTML body, ready to be
// passed to smtp.SendMail.
//
// All user‑supplied fields (userName, subject, feedbackContent) are escaped
// using html.EscapeString to prevent HTML injection.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email address format (good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Escape user input for safe inclusion in the email header and HTML body.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// Build the subject line. For pure ASCII this is fine; for non‑ASCII
	// characters a more elaborate encoding (RFC 2047) would be required.
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Assemble the RFC 5322 headers.
	// The final "\r\n\r\n" separates headers from the body.
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Construct the HTML body.  We wrap the feedback in a <pre> block
	// while preserving line breaks because the content is already escaped.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedbackContent,
	)

	// Combine headers and body to form the complete RFC 5322 message.
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

