package main

import (
	"fmt"
	"net/mail"
	"net/smtp"
	"os"
	"strings"
	"html"
)

// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body containing the user feedback information.
// The returned emailBody includes headers and the body, ready to be sent via
// smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses (RFC 5322)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize the subject to prevent SMTP header injection
	sanitizedSubject := sanitizeHeaderValue(subject)

	// Escape user‑provided data for safe inclusion in HTML
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedback := html.EscapeString(feedbackContent)

	// Build the Subject header
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	// Construct the RFC 5322 headers
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Build the HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedback,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// sanitizeHeaderValue removes control characters (including CR/LF) from a
// string to block SMTP header injection attacks. It keeps printable ASCII,
// space and tab.
func sanitizeHeaderValue(val string) string {
	return strings.Map(func(r rune) rune {
		if (r >= 32 && r <= 126) || r == '\t' {
			return r
		}
		return -1 // drop
	}, val)
}

// main demonstrates how to build a feedback email and send it via SMTP.
func main() {
	// Example input values
	from := "user@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Bug in login page"
	feedbackContent := "I cannot log in when using special characters like <script>alert('xss')</script>.\n\nSteps to reproduce:\n1. Go to login page\n2. Enter credentials\n3. Click login"

	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, feedbackContent)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to build email: %v\n", err)
		os.Exit(1)
	}

	// Print the generated email (for demonstration)
	fmt.Println("Generated email:")
	fmt.Println(emailBody)

	// Send the email using net/smtp.  In production you would use a real
	// SMTP server, TLS, and appropriate authentication.
	err = smtp.SendMail("mail.example.com:25",
		nil, // no auth
		from,
		[]string{to},
		[]byte(emailBody))
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to send email: %v\n", err)
		// For demo purposes we don't treat this as a fatal error.
	} else {
		fmt.Println("Email sent successfully")
	}
}

