const CRLF = "\r\n"

// BuildFeedbackEmail constructs an RFC‑5322‑compliant e‑mail message
// with an HTML body that contains the user feedback information.
//
// The returned emailBody can be passed directly to smtp.SendMail.
// It uses CRLF for line endings, validates addresses with
// net/mail, encodes the subject as an RFC‑2047 encoded‑word when needed,
// escapes HTML‑unsafe characters in the user input and encodes the body
// as quoted‑printable to ensure proper transport.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation: addresses must not be empty
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate e‑mail address format using net/mail
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Escape user input to prevent XSS and header injection
	safeUserName := htmltemplate.EscapeString(userName)
	safeSubject := htmltemplate.EscapeString(subject)
	safeFeedback := htmltemplate.EscapeString(feedbackContent)

	// Encode subject with RFC‑2047 encoded‑word if it contains non‑ASCII
	var encodedSubject string
	if needsNonASCII(subject) {
		encodedSubject = mime.QEncoding.Encode("utf-8", subject)
	} else {
		encodedSubject = subject
	}

	// Build header block using CRLF for line endings
	var hdr strings.Builder
	hdr.WriteString("Date: " + time.Now().Format(time.RFC1123Z) + CRLF)
	hdr.WriteString("From: " + fromAddr + CRLF)
	hdr.WriteString("To: " + toAddr + CRLF)
	hdr.WriteString("Subject: " + encodedSubject + CRLF)
	hdr.WriteString("MIME-Version: 1.0" + CRLF)
	hdr.WriteString("Content-Type: text/html; charset=UTF-8" + CRLF)
	hdr.WriteString("Content-Transfer-Encoding: quoted-printable" + CRLF)
	hdr.WriteString(CRLF) // blank line between header and body

	// HTML body with escaped user content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedback,
	)

	// Encode body as quoted‑printable
	var encodedBuf strings.Builder
	encoder := quotedprintable.NewEncoder(&encodedBuf)
	encoder.Encode([]byte(htmlBody), false)
	encodedBody := encodedBuf.String()

	// Combine headers and encoded body
	emailMessage := hdr.String() + encodedBody
	return emailMessage, nil
}

// needsNonASCII returns true if the string contains any character
// outside the ASCII range (Unicode code point > 127).
func needsNonASCII(s string) bool {
	for _, r := range s {
		if r > 127 {
			return true
		}
	}
	return false
}

