	fmt.Fprintf(&buf, "<p><strong>Subject:</strong> %s</p>", html.EscapeString(subject))
	fmt.Fprintf(&buf, "<p><strong>Feedback Content:</strong></p>")
	// Using <pre> to preserve whitespace and line breaks
	fmt.Fprintf(&buf, "<pre>%s</pre>", html.EscapeString(feedbackContent))
	fmt.Fprintf(&buf, "</body></html>")

	return buf.String(), nil
}

