package main

import (
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
	"time"
)

// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body containing the user feedback information.
// The returned emailBody includes the required headers and body, ready
// to be passed to smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email address format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize the subject line to prevent header injection
	subject = strings.TrimSpace(subject)
	subject = strings.ReplaceAll(subject, "\r\n", " ")
	subject = strings.ReplaceAll(subject, "\n", " ")
	subject = strings.ReplaceAll(subject, "\r", " ")

	// Escape user‑provided data for safe inclusion in HTML
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedback := html.EscapeString(feedbackContent)

	// Build the subject line for the email
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// RFC 5322 headers
	dateHdr := time.Now().Format(time.RFC1123Z)
	// Simple Message‑ID; in production use a proper unique value
	msgID := fmt.Sprintf("<%d.%s>", time.Now().UnixNano(), fromAddr)

	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nDate: %s\r\nMessage-ID: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
		dateHdr,
		msgID,
	)

	// HTML body with the feedback details
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedback,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	// Prevent unused import warning for net/smtp – it is used when the caller
	// passes the returned message to smtp.SendMail.
	var _ = smtp.SendMail

	return emailMessage, nil
}

