package main

import (
	"fmt"
	"net/mail"
	"strings"
	"html"
	"mime"
)

// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body containing the user feedback.
// The returned emailBody includes all headers and the HTML body, ready to be
// sent via net/smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Basic validation for addresses
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize the subject to prevent email header injection
	sanitizedSubject := sanitizeHeader(subject)

	// Encode the subject using MIME encoded‑word for proper handling of non‑ASCII characters
	encodedSubject := mime.WordEncoder('Q').Encode("UTF-8", sanitizedSubject)

	// Build the header block
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: 7bit\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// Escape user‑supplied data before embedding in HTML to prevent XSS
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(sanitizedSubject)
	safeFeedback := html.EscapeString(feedbackContent)

	// Build the HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedback,
	)

	return headers + htmlBody, nil
}

// sanitizeHeader removes control characters (including CR, LF and other
// characters with ASCII code < 32) from a string to prevent email header
// injection. Tab (ASCII 9) is kept; other control characters are dropped.
func sanitizeHeader(s string) string {
	return strings.Map(func(r rune) rune {
		// Keep printable ASCII and tab
		if r == '\t' || (r >= 32 && r < 127) {
			return r
		}
		// Drop everything else (including CR, LF, NUL, etc.)
		return -1
	}, s)
}

// Optional entry point (not required for the functionality above)
func main() {}

