// The email includes the From, To, and Subject headers required by SMTP.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Basic validation
	if fromAddr == "" {
		return "", errors.New("sender address is required")
	}
	if toAddr == "" {
		return "", errors.New("recipient address is required")
	}
	if userName == "" {
		return "", errors.New("user name is required")
	}
	if subject == "" {
		return "", errors.New("feedback subject is required")
	}
	if feedbackContent == "" {
		return "", errors.New("feedback content is required")
	}

	// Escape user input for safe inclusion in HTML
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedback := html.EscapeString(feedbackContent)

	// Build HTML body
	htmlBody := fmt.Sprintf(`<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
</head>
<body>
    <h2>User Feedback</h2>
    <p><strong>Username:</strong> %s</p>
    <p><strong>Subject:</strong> %s</p>
    <p><strong>Feedback:</strong></p>
    <pre style="white-space:pre-wrap; word-wrap:break-word;">%s</pre>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedback)

	// Assemble the full email with RFC 822-style headers
	// Headers must be separated by CRLF (\r\n) and terminated with an extra \r\n before the body.
	var msg strings.Builder
	msg.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msg.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msg.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	msg.WriteString("\r\n")
	msg.WriteString(htmlBody)

	return msg.String(), nil
}

func main() {
	// Example data – replace these with real values or read from user input.
	fromAddr := "user@example.com"
	toAddr := "support@yourcompany.com"
	userName := "John Doe"
	subject := "Bug report: login page crashes"
	feedbackContent := "When I try to log in with a valid username and password,\nthe page crashes and shows a 500 error.\n\nSteps to reproduce:\n1. Go to https://example.com/login\n2. Enter credentials\n3. Click Login"

	// Build the email
