package main

import (
    "fmt"
    "html"
    "net/mail"
    "os"
)

// BuildFeedbackEmail constructs an RFC 5322 compliant email message with an HTML
// body containing the user feedback. It returns the full message (headers + body)
// ready to be passed to smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
    // Basic validation
    if fromAddr == "" || toAddr == "" {
        return "", fmt.Errorf("fromAddr and toAddr must not be empty")
    }

    // Validate email address formats
    if _, err := mail.ParseAddress(fromAddr); err != nil {
        return "", fmt.Errorf("invalid fromAddr: %w", err)
    }
    if _, err := mail.ParseAddress(toAddr); err != nil {
        return "", fmt.Errorf("invalid toAddr: %w", err)
    }

    // Build subject line for the email header
    emailSubject := fmt.Sprintf("Feedback: %s", subject)

    // Use CRLF for line endings
    crlf := "\r\n"

    // Escape user input for safe inclusion in HTML
    escapedUserName := html.EscapeString(userName)
    escapedSubject := html.EscapeString(subject)
    escapedFeedback := html.EscapeString(feedbackContent)

    // Construct the RFC 5322 headers
    headerFmt := "From: %s%sTo: %s%sSubject: %s%sMIME-Version: 1.0%sContent-Type: text/html; charset=UTF-8%s%s"
    headers := fmt.Sprintf(headerFmt,
        fromAddr, crlf,
        toAddr, crlf,
        emailSubject, crlf,
        crlf,
        crlf,
    )

    // Build the HTML body
    htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
        escapedUserName,
        escapedSubject,
        escapedFeedback,
    )

    // Combine headers and body
    emailMessage := headers + htmlBody

    return emailMessage, nil
}

func main() {
    // Example usage
    body, err := BuildFeedbackEmail(
        "sender@example.com",
        "support@example.com",
        "John Doe",
        "Bug report",
        "I encountered a problem when trying to log in.\nThe page shows a 500 error.",
    )
    if err != nil {
        fmt.Fprintln(os.Stderr, "Error:", err)
        os.Exit(1)
    }
    fmt.Println(body)
}

