// BuildFeedbackEmail constructs a complete RFC 5322‑compliant email message
// with an HTML body containing the user‑submitted feedback.
// The returned emailBody includes headers and body, ready to be sent via
// smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation: both addresses must be supplied.
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate the format of the addresses – this also rejects strings
	// that contain line‑break characters.
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Helper to strip any line‑break characters from header values.
	sanitize := func(s string) string {
		return strings.NewReplacer("\r", "", "\n", "", "\r\n", "").Replace(s)
	}

	// Clean the user‑provided subject for the SMTP header.
	cleanSubject := sanitize(subject)

	// HTML‑escape the user‑provided strings that will appear in the message body.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(cleanSubject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// Build the subject line.  The format is fixed, so no extra CRLF can appear.
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Assemble the RFC 5322 header block.  All values have already been
	// sanitised against header injection.
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Create the HTML body with the escaped user data.
	htmlBody := fmt.Sprintf(
		"<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <title>User Feedback</title>\n</head>\n<body>\n  <h2>User Feedback Received</h2>\n  <p><strong>Submitted by:</strong> %s</p>\n  <p><strong>Subject:</strong> %s</p>\n  <div><strong>Message:</strong><br>\n    <pre style=\"font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;\">%s</pre>\n  </div>\n</body>\n</html>",
		safeUserName,
		safeSubject,
		safeFeedbackContent,
	)

	// Combine headers and body into the final message.
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

